// Instead of looping over all <li> elements, we attach ONE listener to the <ul>
const ul = document.querySelector('#todo-list');

ul.addEventListener('click', function(e) {
  // Check if what was clicked was actually a delete button
  if (e.target.classList.contains('delete-btn')) {
    // We found the button! Now remove its parent <li>
    const li = e.target.closest('li');
    li.remove();
  }
});

// Even if we add new <li> items later with JavaScript, the <ul> 
// will still catch their clicks automatically! No new listeners needed.
